const d = $input.first().json;

function priorityEmoji(p) {
  if (p === 'high') return ' 🔴';
  if (p === 'medium') return ' 🟡';
  return '';
}

function fmtActionItem(item, index) {
  let line = `${index}. **${item.title}**`;
  if (item.project) line += ` \`[${item.project}]\``;
  line += priorityEmoji(item.priority);
  if (item.due) line += `\n   Due: ${item.due}`;
  return line;
}

const lines = [`**Second Brain – Daily Brief** | ${d.today}`, ''];

// Focus items: due today + high-priority open
const focusItems = [...(d.due_today ?? []), ...(d.focus_items ?? [])];
if (focusItems.length > 0) {
  lines.push("**Today's Focus**");
  focusItems.slice(0, 7).forEach((item, i) => lines.push(fmtActionItem(item, i + 1)));
  lines.push('');
}

// Coming up (next 7 days — tasks with due dates + events)
if ((d.coming_up ?? []).length > 0) {
  lines.push('**Coming Up**');
  d.coming_up.forEach(item => {
    const label = item.title ?? item.name ?? '';
    lines.push(`- ${item.date}: ${label}`);
  });
  lines.push('');
}

// Birthdays (next 14 days)
if ((d.birthdays ?? []).length > 0) {
  lines.push('**Upcoming Birthdays**');
  d.birthdays.forEach(b => lines.push(`- 🎂 ${b.name} – ${b.date}`));
  lines.push('');
}

// Pending tasks (capped at 10)
const pending = d.pending_tasks ?? [];
if (pending.length > 0) {
  const shown = pending.slice(0, 10);
  const extra = pending.length - shown.length;
  lines.push(`**Pending Tasks** (${pending.length})`);
  shown.forEach(item => {
    const proj = item.project ? `[${item.project}] ` : '';
    lines.push(`- ${proj}${item.title}`);
  });
  if (extra > 0) lines.push(`- _…and ${extra} more_`);
  lines.push('');
}

// Stale / neglected (no update in 7+ days)
if ((d.stale_tasks ?? []).length > 0) {
  lines.push('**Stale / Neglected**');
  (d.stale_tasks ?? []).slice(0, 5).forEach(item => {
    const proj = item.project ? `[${item.project}] ` : '';
    lines.push(`- ${proj}${item.title}`);
  });
  lines.push('');
}

const total = focusItems.length + (d.coming_up ?? []).length + (d.birthdays ?? []).length
  + pending.length + (d.stale_tasks ?? []).length;
if (total === 0) {
  lines.push('_Nothing on the radar today. ✨_');
}

return [{ json: { content: lines.join('\n').trim() } }];

// Digest delivery to Discord failed. Log safe metadata only — no capture content.
console.log(JSON.stringify({
  event: 'digest_delivery_failed',
  workflow: 'second_brain_daily_digest',
  error_description: $input.first().json?.error?.description ?? 'unknown',
  error_status: $input.first().json?.error?.httpCode ?? null,
  timestamp: new Date().toISOString(),
}));
return [{ json: { recorded: true, delivery_failed: true } }];
